async function authMiddleware(c, next) {
  const headers = new Headers;
  for (const [key, val] of Object.entries(c.req.header())) {
    if (val !== undefined) {
      headers.set(key, val);
    }
  }
  const session4 = await auth.api.getSession({ headers });
  if (!session4) {
    return c.json({ detail: "Missing or invalid authorization" }, 401);
  }
  if (!session4.user.isActive) {
    return c.json({ detail: "User not found or deactivated" }, 401);
  }
  c.set("user", session4.user);
  c.set("userId", session4.user.id);
  c.set("userRole", session4.user.role);
  await next();
}
